import { v4 as uuidv4 } from 'uuid';
import {
	ALIGNMENT,
	ConcreteEncounter,
	ConcreteEncounterVariant,
	DIFFICULTY,
	LEVEL_REPRESENTATION,
	type NarrativeSlot,
	type Participant,
} from '@/store/data';
import {
	computeBuilderXP,
	normalizeSideType,
	type BuilderSlot,
	type SideType,
} from './builderXp';
import { Threat } from '@/models/utility/threat/Threat.class';
import type { LevelAdjustment } from '@/models/utility/level/Level';
import type { EncounterTemplateData } from '@/models/encounters/encounter.types';

export interface BuilderVariantSnapshot {
	id: string;
	description: string;
	partyLevel: number;
	partySize: number;
	slots: BuilderSlot[];
}

export interface BuilderFormValues {
	name: string;
	description: string;
	partyLevel: number;
	partySize: number;
	variants: BuilderVariantSnapshot[];
	gmNotes: string;
	monsterNotes: string;
	playerNotes: string;
	slots: BuilderSlot[];
}

export function defaultSlot(): BuilderSlot {
	return {
		id: uuidv4(),
		type: 'creature',
		name: '',
		description: '',
		side: 'opponent',
		level: 1,
		count: 1,
		maxHealth: undefined,
		hardness: undefined,
		initiativeBonus: undefined,
		initiativeDescription: undefined,
		dcs: [],
		successesToDisable: 1,
		adjustment: 'none',
		adjustmentDescription: undefined,
		adjustmentLevelModifier: undefined,
		isSimpleHazard: false,
		reinforcementRound: 1,
		reinforcementParticipants: [],
		eventRound: 1,
		repeatInterval: undefined,
		accomplishmentLevel: 'story',
		traits: [],
		combatReadyState: 'active',
		initiativeModifier: undefined,
		hiddenFromPlayers: false,
	};
}

function alignmentToBuilderSide(side: number): SideType {
	if (side === ALIGNMENT.PCs) {
		return 'ally';
	}

	if (side === ALIGNMENT.Neutral) {
		return 'other';
	}

	return 'opponent';
}

function builderSideToAlignment(
	side: SideType
): (typeof ALIGNMENT)[keyof typeof ALIGNMENT] {
	const normalizedSide = normalizeSideType(side);

	if (normalizedSide === 'ally') {
		return ALIGNMENT.PCs;
	}

	if (normalizedSide === 'other') {
		return ALIGNMENT.Neutral;
	}

	return ALIGNMENT.Opponents;
}

export function defaultFormValues(): BuilderFormValues {
	return {
		name: '',
		description: '',
		partyLevel: 1,
		partySize: 4,
		variants: [],
		gmNotes: '',
		monsterNotes: '',
		playerNotes: '',
		slots: [],
	};
}

export function fromEncounterTemplate(
	template: EncounterTemplateData,
	variant: EncounterTemplateData['variants'][number],
	options?: {
		partyLevel?: number;
		partySize?: number;
	}
): BuilderFormValues {
	const partyLevel = options?.partyLevel ?? variant.partyLevel ?? 1;
	const partySize = options?.partySize ?? variant.partySize ?? 4;

	return {
		name: template.name,
		description: template.description,
		partyLevel,
		partySize,
		variants: [],
		gmNotes: '',
		monsterNotes: '',
		playerNotes: '',
		slots: variant.participants.map((participant) => ({
			id: participant.id,
			type: participant.type === 'creature' ? 'creature' : 'hazard',
			name:
				participant.type === 'creature'
					? `${participant.role || 'creature'} (${participant.count})`
					: participant.id,
			description: '',
			side: alignmentToBuilderSide(participant.side),
			level: participant.relativeLevel.toLevel(partyLevel).valueOf(),
			count: participant.count,
				maxHealth:
					participant.type === 'creature'
						? participant.maxHealthOverride
						: undefined,
				hardness:
					participant.type === 'hazard' ? participant.hardnessValue : undefined,
				initiativeBonus:
					participant.type === 'creature'
						? participant.initiativeModifierOverride
						: undefined,
				dcs: [],
			successesToDisable:
				participant.type === 'hazard' ? participant.successesToDisable : 1,
			adjustment: 'none',
				adjustmentDescription: undefined,
				adjustmentLevelModifier: undefined,
			isSimpleHazard:
				participant.type === 'hazard' && participant.role === 'simple',
			reinforcementRound: 1,
			reinforcementParticipants: [],
			eventRound: 1,
			repeatInterval: undefined,
			accomplishmentLevel: undefined,
		})),
	};
}

function threatToDifficulty(
	threatKey: number
): ConcreteEncounter['difficulty'] {
	if (threatKey <= 0) return DIFFICULTY.Trivial;

	if (threatKey === 1) return DIFFICULTY.Low;

	if (threatKey <= 3) return DIFFICULTY.Moderate;

	if (threatKey <= 5) return DIFFICULTY.Severe;

	return DIFFICULTY.Extreme;
}

function toRelativeLevelString(level: number, partyLevel: number): `+${number}` | `-${number}` {
	const diff = Math.trunc(level - partyLevel);
	const signed = `${diff >= 0 ? '+' : ''}${diff}`;

	return signed as `+${number}` | `-${number}`;
}

function fromRelativeLevelString(relativeLevel: string, partyLevel: number): number {
	const parsed = Number(relativeLevel);

	if (!Number.isFinite(parsed)) {
		return partyLevel;
	}

	return partyLevel + parsed;
}

export function toConcreteEncounter(
	values: BuilderFormValues,
	existingId?: string
): ConcreteEncounter {
	const id = existingId ?? uuidv4();
	const xp = computeBuilderXP(values.slots, values.partyLevel);
	const threat = Threat.fromExperienceBudget(xp, values.partySize);
	const difficulty = threatToDifficulty(threat.threat);

	const participants: Participant<typeof LEVEL_REPRESENTATION.Exact>[] = values.slots
		.filter((s) => s.type === 'creature' || s.type === 'hazard')
		.map((s) => {
			const side = builderSideToAlignment(s.side);

			if (s.type === 'hazard') {
				return {
					type: 'hazard' as const,
					name: s.name,
					level: s.level,
					side,
					count: s.count,
					maxHealth: s.maxHealth || undefined,
					hardness: s.hardness || undefined,
					initiativeBonus: s.initiativeBonus || undefined,
					dcs:
						s.dcs && s.dcs.length > 0
							? s.dcs
								.map((dc) => ({
									...dc,
									name: dc.name ?? dc.inline,
								}))
								.filter((dc) => (dc.name ?? dc.inline ?? '').trim().length > 0)
							: undefined,
					successesToDisable: s.successesToDisable ?? 1,
					isComplexHazard: !s.isSimpleHazard,
					adjustmentDescription: s.adjustmentDescription || undefined,
					adjustmentLevelModifier:
						typeof s.adjustmentLevelModifier === 'number' &&
						Number.isFinite(s.adjustmentLevelModifier)
							? s.adjustmentLevelModifier
							: undefined,
					description: s.description || undefined,
				};
			}

			return {
				type: 'creature' as const,
				name: s.name,
				level: s.level,
				side,
				count: s.count,
				maxHealth: s.maxHealth || undefined,
				hardness: s.hardness || undefined,
				initiativeBonus: s.initiativeBonus || undefined,
				dcs:
					s.dcs && s.dcs.length > 0
						? s.dcs
							.map((dc) => ({
								...dc,
								name: dc.name ?? dc.inline,
							}))
							.filter((dc) => (dc.name ?? dc.inline ?? '').trim().length > 0)
						: undefined,
				adjustment:
					s.adjustment === 'none'
						? undefined
						: (s.adjustment as LevelAdjustment),
				adjustmentDescription: s.adjustmentDescription || undefined,
				adjustmentLevelModifier:
					typeof s.adjustmentLevelModifier === 'number' &&
					Number.isFinite(s.adjustmentLevelModifier)
						? s.adjustmentLevelModifier
						: undefined,
				description: s.description || undefined,
			};
		});

	const narrativeSlots: NarrativeSlot[] = values.slots
		.filter(
			(s) => s.type === 'narrative' || s.type === 'reinforcement'
		)
		.map((s) => ({
			id: s.id,
			type:
				s.type === 'reinforcement'
						? ('reinforcement' as const)
						: s.repeatInterval
							? ('ongoing' as const)
							: ('default' as const),
			description: s.description || undefined,
			accomplishmentLevel:
				s.type === 'reinforcement' ? undefined : s.accomplishmentLevel,
			trigger: {
				round: s.type === 'reinforcement' ? s.reinforcementRound : s.eventRound,
				frequency:
					s.type === 'reinforcement' ? undefined : s.repeatInterval || undefined,
			},
			participants:
				s.type === 'reinforcement'
					? s.reinforcementParticipants.map((participant) => {
							const side = builderSideToAlignment(participant.side);

							if (participant.type === 'hazard') {
								return {
									type: 'hazard' as const,
									name: participant.name,
									level: toRelativeLevelString(participant.level, values.partyLevel),
									side,
									count: participant.count,
									maxHealth: participant.maxHealth || undefined,
									hardness: participant.hardness || undefined,
									initiativeBonus: participant.initiativeBonus || undefined,
									dcs:
										participant.dcs && participant.dcs.length > 0
											? participant.dcs
												.map((dc) => ({
													...dc,
													name: dc.name ?? dc.inline,
												}))
												.filter((dc) => (dc.name ?? dc.inline ?? '').trim().length > 0)
											: undefined,
									successesToDisable: participant.successesToDisable,
									isComplexHazard: !participant.isSimpleHazard,
									adjustmentDescription:
										participant.adjustmentDescription || undefined,
									adjustmentLevelModifier:
										typeof participant.adjustmentLevelModifier === 'number' &&
										Number.isFinite(participant.adjustmentLevelModifier)
											? participant.adjustmentLevelModifier
											: undefined,
								};
							}

							return {
								type: 'creature' as const,
								name: participant.name,
								level: toRelativeLevelString(participant.level, values.partyLevel),
								side,
								count: participant.count,
								maxHealth: participant.maxHealth || undefined,
								hardness: participant.hardness || undefined,
								initiativeBonus: participant.initiativeBonus || undefined,
								dcs:
									participant.dcs && participant.dcs.length > 0
										? participant.dcs
											.map((dc) => ({
												...dc,
												name: dc.name ?? dc.inline,
											}))
											.filter((dc) => (dc.name ?? dc.inline ?? '').trim().length > 0)
										: undefined,
								adjustment:
									participant.adjustment !== 'none'
										? participant.adjustment
										: undefined,
								adjustmentDescription:
									participant.adjustmentDescription || undefined,
								adjustmentLevelModifier:
									typeof participant.adjustmentLevelModifier === 'number' &&
									Number.isFinite(participant.adjustmentLevelModifier)
										? participant.adjustmentLevelModifier
										: undefined,
							};
						})
					: undefined,
		}));
	const variants: ConcreteEncounterVariant[] | undefined =
		values.variants.length > 0
			? values.variants.map((snapshot) => {
					const snapXp = computeBuilderXP(snapshot.slots, snapshot.partyLevel);
					const snapThreat = Threat.fromExperienceBudget(snapXp, snapshot.partySize);
					const snapParticipants: Participant<typeof LEVEL_REPRESENTATION.Exact>[] =
						snapshot.slots
							.filter((s) => s.type === 'creature' || s.type === 'hazard')
							.map((s) => {
								const side =
									builderSideToAlignment(s.side);

								if (s.type === 'hazard') {
									return {
										type: 'hazard' as const,
										name: s.name,
										level: s.level,
										side,
										count: s.count,
										maxHealth: s.maxHealth || undefined,
										hardness: s.hardness || undefined,
										initiativeBonus: s.initiativeBonus || undefined,
										dcs: s.dcs,
										successesToDisable: s.successesToDisable ?? 1,
										isComplexHazard: !s.isSimpleHazard,
										adjustmentDescription: s.adjustmentDescription || undefined,
										adjustmentLevelModifier:
											typeof s.adjustmentLevelModifier === 'number' &&
											Number.isFinite(s.adjustmentLevelModifier)
												? s.adjustmentLevelModifier
												: undefined,
										description: s.description || undefined,
									};
								}

								return {
									type: 'creature' as const,
									name: s.name,
									level: s.level,
									side,
									count: s.count,
									maxHealth: s.maxHealth || undefined,
									hardness: s.hardness || undefined,
									initiativeBonus: s.initiativeBonus || undefined,
									dcs: s.dcs,
									adjustment:
										s.adjustment === 'none'
											? undefined
											: (s.adjustment as LevelAdjustment),
									adjustmentDescription: s.adjustmentDescription || undefined,
									adjustmentLevelModifier:
										typeof s.adjustmentLevelModifier === 'number' &&
										Number.isFinite(s.adjustmentLevelModifier)
											? s.adjustmentLevelModifier
											: undefined,
									description: s.description || undefined,
								};
							});

					return {
						level: snapshot.partyLevel,
						partySize: snapshot.partySize,
						difficulty: threatToDifficulty(snapThreat.threat),
						description: snapshot.description.trim() || `Variant`,
						participants: snapParticipants,
					};
				})
			: undefined;

	return {
		id,
		name: values.name,
		levelRepresentation: LEVEL_REPRESENTATION.Exact,
		level: values.partyLevel,
		partySize: values.partySize,
		difficulty,
		description: values.description,
		participants,
		variants,
		narrativeSlots: narrativeSlots.length > 0 ? narrativeSlots : undefined,
		notes: {
			gm: values.gmNotes || undefined,
			monster: values.monsterNotes || undefined,
			player: values.playerNotes || undefined,
		},
	};
}

export function fromConcreteEncounter(
	encounter: ConcreteEncounter
): BuilderFormValues {
	const slots: BuilderSlot[] = [];

	for (const p of encounter.participants) {
		if (p.type === 'creature') {
			slots.push({
				id: uuidv4(),
				type: 'creature',
				name: p.name,
				description: p.description ?? '',
				side: alignmentToBuilderSide(p.side),
				level: p.level,
				count: p.count ?? 1,
				maxHealth: p.maxHealth,
				hardness: p.hardness,
				initiativeBonus: p.initiativeBonus,
				dcs: p.dcs ?? [],
				successesToDisable: 1,
				adjustment: p.adjustment ?? 'none',
				adjustmentDescription: p.adjustmentDescription,
				adjustmentLevelModifier: p.adjustmentLevelModifier,
				isSimpleHazard: false,
				reinforcementRound: 1,
				reinforcementParticipants: [],
				eventRound: 1,
				repeatInterval: undefined,
				accomplishmentLevel: undefined,
			});
			continue;
		}

		slots.push({
			id: uuidv4(),
			type: 'hazard',
			name: p.name,
			description: p.description ?? '',
			side: alignmentToBuilderSide(p.side),
			level: p.level,
			count: p.count ?? 1,
			maxHealth: p.maxHealth,
			hardness: p.hardness,
			initiativeBonus: p.initiativeBonus,
			dcs: p.dcs ?? [],
			successesToDisable: p.successesToDisable,
			adjustment: 'none',
			adjustmentDescription: p.adjustmentDescription,
			adjustmentLevelModifier: p.adjustmentLevelModifier,
			isSimpleHazard: !p.isComplexHazard,
			reinforcementRound: 1,
			reinforcementParticipants: [],
			eventRound: 1,
			repeatInterval: undefined,
			accomplishmentLevel: undefined,
		});
	}

	for (const ns of encounter.narrativeSlots ?? []) {
		const isReinforcement = ns.type === 'reinforcement';

		slots.push({
			id: ns.id,
			type: isReinforcement ? 'reinforcement' : 'narrative',
			name: '',
			description: ns.description ?? '',
			side: 'opponent',
			level: encounter.level,
			count: 1,
			maxHealth: undefined,
			successesToDisable: 1,
			adjustment: 'none',
			isSimpleHazard: false,
			reinforcementRound: ns.trigger.round,
			reinforcementParticipants: isReinforcement
				? (ns.participants ?? []).map((participant) => ({
						id: uuidv4(),
						type: participant.type,
						name: participant.name,
						side: alignmentToBuilderSide(participant.side),
						level: fromRelativeLevelString(participant.level, encounter.level),
						count: participant.count ?? 1,
						maxHealth: participant.maxHealth,
						hardness: participant.hardness,
						initiativeBonus: participant.initiativeBonus,
						dcs: participant.dcs ?? [],
						successesToDisable:
							participant.type === 'hazard'
								? participant.successesToDisable
								: 1,
						adjustment:
							participant.type === 'creature'
								? (participant.adjustment ?? 'none')
								: 'none',
						adjustmentDescription: participant.adjustmentDescription,
						adjustmentLevelModifier: participant.adjustmentLevelModifier,
						isSimpleHazard:
							participant.type === 'hazard' ? !participant.isComplexHazard : false,
					}))
				: [],
			eventRound: ns.trigger.round,
			repeatInterval: ns.trigger.frequency,
			accomplishmentLevel: isReinforcement
				? undefined
				: (ns.accomplishmentLevel ?? 'story'),
		});
	}

	return {
		name: encounter.name,
		description: encounter.description,
		partyLevel: encounter.level,
		partySize: encounter.partySize,
		variants: encounter.variants?.map((v) => ({
			id: uuidv4(),
			description: v.description,
			partyLevel: v.level ?? encounter.level,
			partySize: v.partySize ?? encounter.partySize,
			slots: participantsToBuilderSlots(v.participants),
		})) ?? [],
		gmNotes: encounter.notes?.gm ?? '',
		monsterNotes: encounter.notes?.monster ?? '',
		playerNotes: encounter.notes?.player ?? '',
		slots,
	};
}

function participantsToBuilderSlots(
	participants: Participant<typeof LEVEL_REPRESENTATION.Exact>[]
): BuilderSlot[] {
	return participants.map((p) => {
		if (p.type === 'creature') {
			return {
				id: uuidv4(),
				type: 'creature' as const,
				name: p.name,
				description: p.description ?? '',
				side: alignmentToBuilderSide(p.side),
				level: p.level,
				count: p.count ?? 1,
				maxHealth: p.maxHealth,
				hardness: p.hardness,
				initiativeBonus: p.initiativeBonus,
				dcs: p.dcs ?? [],
				successesToDisable: 1,
				adjustment: p.adjustment ?? 'none',
				adjustmentDescription: p.adjustmentDescription,
				adjustmentLevelModifier: p.adjustmentLevelModifier,
				isSimpleHazard: false,
				reinforcementRound: 1,
				reinforcementParticipants: [],
				eventRound: 1,
				repeatInterval: undefined,
				accomplishmentLevel: undefined,
			};
		}

		return {
			id: uuidv4(),
			type: 'hazard' as const,
			name: p.name,
			description: p.description ?? '',
			side: alignmentToBuilderSide(p.side),
			level: p.level,
			count: p.count ?? 1,
			maxHealth: p.maxHealth,
			hardness: p.hardness,
			initiativeBonus: p.initiativeBonus,
			dcs: p.dcs ?? [],
			successesToDisable: p.successesToDisable,
			adjustment: 'none',
			adjustmentDescription: p.adjustmentDescription,
			adjustmentLevelModifier: p.adjustmentLevelModifier,
			isSimpleHazard: !p.isComplexHazard,
			reinforcementRound: 1,
			reinforcementParticipants: [],
			eventRound: 1,
			repeatInterval: undefined,
			accomplishmentLevel: undefined,
		};
		});
}

/**
 * Produces form-loadable values from a template variant (for shadow-variant loading).
 * Converts relative participant levels to absolute using the given partyLevel.
 */
export function templateVariantToFormPartial(
	variant: import('@/models/encounters/encounter.types').EncounterVariant,
	partyLevel: number
): { partySize: number; slots: BuilderSlot[] } {
	return {
		partySize: variant.partySize,
		slots: variant.participants.map((participant) => ({
			id: participant.id,
			type: participant.type === 'creature' ? 'creature' as const : 'hazard' as const,
			name:
				participant.type === 'creature'
					? `${participant.role || 'creature'} (${participant.count})`
					: participant.id,
			description: '',
			side: alignmentToBuilderSide(participant.side),
			level: participant.relativeLevel.toLevel(partyLevel).valueOf(),
			count: participant.count,
			maxHealth:
				participant.type === 'creature'
					? participant.maxHealthOverride
					: undefined,
			hardness:
				participant.type === 'hazard' ? participant.hardnessValue : undefined,
			initiativeBonus:
				participant.type === 'creature'
					? participant.initiativeModifierOverride
					: undefined,
			dcs: [],
			successesToDisable:
				participant.type === 'hazard' ? participant.successesToDisable : 1,
			adjustment: 'none',
			adjustmentDescription: undefined,
			adjustmentLevelModifier: undefined,
			isSimpleHazard:
				participant.type === 'hazard' && participant.role === 'simple',
			reinforcementRound: 1,
			reinforcementParticipants: [],
			eventRound: 1,
			repeatInterval: undefined,
			accomplishmentLevel: undefined,
		})),
	};
}
